# Category: command_injection

class ImagesController < ApplicationController
  def process
    if params[:image] && params[:format] && params[:size]
      image = params[:image].tempfile.path
      output_format = params[:format]
      size = params[:size]

      output_file = "output.#{output_format}"
      command = "convert #{image} -resize #{size} #{output_file}"

      system(command)

      send_file(output_file, type: "image/#{output_format}", disposition: 'inline')
    else
      render json: { error: 'Missing required parameters' }, status: :bad_request
    end
  end
end